	// DFCT0010343 - TUP - Filter was not working for OU Templates in Template LIst screen - issue introduced in 2.6
	function loadAttachmentsWidgets() {
		if (c.data.SNAttachmentsON == true) {
			// STRY0063505 The Process Template is using "Attachments" as the "Shared Attachments" for the Process Tree
			if (c.data.table != "x_153465_discovert_discover_routing_template" || c.data.AttachmentSharedFolderON == true) {
				// DFCT0010343 - TUP - Filter was not working for OU Templates in Template LIst screen - issue introduced in 2.6
				c.data.myAttachmentWidget = null;

				spUtil.get('tasker_task_attachments', {
					// 2.7.2 | 2022-01-26 | mmcc | STRY0110656 - UI- Fixed Header and Button Bars on ALL Modals and lists; added isModal
					isModal: c.data.isModal,
					table: c.data.table,
					sys_id: c.data.sys_id,
					name: 'myAttachmentWidget'
				}).then(function(response) {
					c.data.myAttachmentWidget = response;
				});
			}
		}
		if ((c.data.AttachmentSharedFolderON == true) && (c.data.SNAttachmentsON == true)) {
			// DFCT0010343 - TUP - Filter was not working for OU Templates in Template LIst screen - issue introduced in 2.6
			c.data.sharedAttachmentWidget = null;
			spUtil.get('tasker_task_attachments', {
				// 2.7.2 | 2022-01-26 | mmcc | STRY0110656 - UI- Fixed Header and Button Bars on ALL Modals and lists; added isMOdal
				isModal: c.data.isModal,
				table: c.data.sharedAttachTableName,
				sys_id: c.data.sharedAttachSys_ID + "",
				name: 'sharedAttachmentWidget'
			}).then(function(response) {
				c.data.sharedAttachmentWidget = response;
			});
		}

	}


	function addActiveCssClass() {
		var resetActiveTabe = false;
		if ((c.data.table == 'x_153465_discovert_discover_office_hierarchy' && 
			 $scope.data.page_id == 'discovertasker_officehierarchy') ||
			(c.data.table == 'x_153465_discovert_route_tasks' && 
			 $scope.data.page_id == 'discovertasker_processtemplatedetails')) {
			resetActiveTabe = true;
		}
		if ($scope.data.page_id == 'discovertasker_detailsdrilldown' || 
			$scope.data.page_id == 'discovertasker_taskdetails') {
			resetActiveTabe = true;
		}
		if(resetActiveTabe == true){
			$(".nav-tabs li")
				.removeClass("active");
			$(".nav-tabs li:first-child")
				.addClass("active");
			$(".tab-content div")
				.removeClass("active");
			$(".tab-content div:first-child")
				.addClass("active");
		}
	}

	// 2.7.0 | 2021-05-21 | mmcc | STRY0099596 Record Watcher on Template Count not Updating; emit sends rowCount in params, no need for .Deleted or .Added
