	// 2.7.0 | 2021-05-21 | mmcc | STRY0099596 Record Watcher on Template Count not Updating; emit sends rowCount in params, no need for .Deleted or .Added
	$scope.$on("sp.DiscoverListItem", function(event, params) {
		c.data.f._related_lists.forEach(function(relatedList) {
			if(relatedList.table == params.table && relatedList.filter == params.filter ) {
				relatedList.count = params.rowCount;
			}
		});
	});

	// STRY0059178 | Shared Documents Folder
	$scope.$on("tasker_task_attachments.count", function(event, e) {

		if (e) {
			if (e.source == 'sharedAttachmentWidget') {
				if (e.count) {
					$scope.data.sharedAttachmentWidgetCount = e.count;
				} else {
					$scope.data.sharedAttachmentWidgetCount = 0;
				}
			}
			if (e.source == 'myAttachmentWidget') {
				if (e.count) {
					$scope.data.myAttachmentWidgetCount = e.count;
				} else {
					$scope.data.myAttachmentWidgetCount = 0;
				}

			}
		}
	});

	// FOR THE RELATED LIST TO REFRESH THE URL
	$scope.$on('data_table.click', function(e, parms) {
		if(c.data.table == parms.table && c.data.sys_id != parms.sys_id){
			$rootScope.$broadcast('$taskerTabbedForm.drillDownList.click', parms);
			$location.search('table', parms.table).search('sys_id', parms.sys_id).search('spa', '1');
		}

		onListClick(e, parms);
	});

	$scope.openNewModal = function(table, title, view, query, sys_id) {
		// If the form is dirty, ask the user if they would like to save the record
		var fMsg = '';
		var serializeChanges = g_form.serialize(true);
		if(serializeChanges.length>0){
			var changeFieldList = [];
			for (var field in serializeChanges) {
				changeFieldList.push(serializeChanges[field].label.trim());
			}
			fMsg = changeFieldList.join(', ');

			spModal.confirm("${Tasker - Modal Save Changes Message}  "+ fMsg).then(function(confirmed) {
				g_form.save();
				open_New_Modal(table, title, view, query, sys_id);
			});
		}else{
			open_New_Modal(table, title, view, query, sys_id);
		}

	};

	// STRY0097476 New Email
	$scope.openModalExportTask = function() {
		g_form.submit('openModalExportTask');
	};

	function open_New_Modal(table, title, view, query, sys_id) {
		var formQuery = query + sys_id;
		spModal.open({
			title: title,
			backdrop:'static',
			widget: 'discovertasker-formtab',
			widgetInput: {
				table: table,
				sys_id: "-1",
				view: view,
				query: formQuery,
				// DFCT0010635
				omitHeader: 'true',
				// STRY0040294 - added isModal - added closing of open modal
				isModal: true //,
			},
			size: 'lg',
			buttons: [],
			// 2.7.2 | 2022-01-26 | mmcc | STRY0110656 - UI- Fixed Header and Button Bars on ALL Modals and lists
			footerStyle: {
				'display': 'none'
			}
		});
	}

	$scope.$on("spModel.uiActionComplete", function(evt, response) {
		// 2021.04.15 - Fix issue with form submit when to reload the form
		// *************** Customization Start ***************************
		// RAJ - Added below to close window when finished
		// STRY0074663
		if (c.data.isModal) {
			$scope.$parent.$parent.$dismiss();
			return;
		} // 09.10
		// *************** Customization End ***************************

		// START - RAJ Remove post back on Modals
		// after reviewing this, there is nothing in here that is required.
		// If a uiaction needs to redirect or refresh the form, it should be done in the UI Action
		// The only thing I noticed that needed to be updated upon removing this is the Create Task UI Action.
		// Every other UI Action opens in a modal and closes then allows the form to refresh using record watchers.
		// NOTE: All of the new item screens use the new task screen.  The OU, Member and Contact always open in a modal.  So, they do not need to refresh the base form.
		// DFCT0010657   The Template and the Task screen redirect to a new page and do not open in a modal
		//               If data.sys_id was -1, then the new item is from thei form.  The Create UI Action for task redirects.  So, the key case should not get here
		//               If data.sys_id is NOT -1, then the response Insert is NOT for this form.
		if ($scope.data.sys_id ==-1 && 
			($scope.data.table == 'x_153465_discovert_route_task_instance' || $scope.data.table == 'x_153465_discovert_discover_routing_template')){
			var sysID = (response && response.isInsert) ? response.sys_id : $scope.data.sys_id;
			var error;
			if (response.$$uiNotification[0]) {
				if (response.$$uiNotification[0].type == "error") {
					error = true;
				} else {
					error = false;
				}
			}

			if (response && response.isInsert && (!error)) {
				// STRY0105791
				var redirectUrlNew;
				switch ($scope.data.table) {
					case 'x_153465_discovert_route_task_instance':
						// STRY0113838 - DFCT0010657
						//							redirectUrlNew = "?id=" + c.data.url_Properties.pageId +
						//							"&view=" + c.data.url_Properties.view +
						//							"&table=" + $scope.data.table + "&sys_id=" + sysID;
						//							$location.url(redirectUrlNew);

						c.data.getURL=true;
						c.data.sys_id=sysID;
						c.data.view=c.data.url_Properties.view;
						c.data.isValid = false;
						c.data.loadingIndicator = true;
						c.data.emptyStateTemplate = false;
						$scope.server.update().then(function(data) {
							redirectUrlNew = data.portal_url_ref + '?id=' +  data.pageId + '&sys_id=' + data.sys_id + '&table=' + data.pageTable + '&view=' + data.view;
							$location.url(redirectUrlNew);
						});


						break;
						// STRY0093947
					case 'x_153465_discovert_discover_routing_template':
						redirectUrlNew = "?id=discovertasker_processtemplatedetails&table=" + $scope.data.table + "&sys_id=" + sysID + "&spa=1";
						$location.url(redirectUrlNew);
						break;
				}
				return;
			}
		}
		// STRY0093904 - "UI Actions" on Task Form are NOT responsive
		$scope.submitting = false;
		// 2021.04.15 - Fix issue with form submit when to reload the form			
		if (response.isActionAborted)
			return;

		loadForm(c.data.table, c.data.sys_id).then(function(response){
			if(!response || !response.isInsert){
				constructResponseHandler(response);
			}
		});
	});

	//------------------------------------------------------------------------------------------------------------------------
	// END CUSTOM
	//------------------------------------------------------------------------------------------------------------------------

	$rootScope.$on('$sp.html.editor.progress', function(e, conf) {
		$scope.submitting = conf.state;
	});

	$rootScope.$broadcast('sp.update.breadcrumbs', $scope.data.breadcrumbs);

	// STRY0108140 - STRY0115840
	$scope.getButtonClass = function(action) {
		// STRY0115840 for Activate OU button, change to different color for emphasis
		// 2.8 | 2022-05-06 | mmcc | STRY0115297 - New Task Form- Allow users to start Tasks as Draft; use style Success
		if(action.sys_id == '5fe1a93ddb9cb780c18c59b2ca961945' ||
			action.sys_id == '01713ba91b538d90d6062023b24bcba4') { // Save as Draft UI Action
			return "btn btn-success action-btn";
		}
		if (action.form_style == "destructive")
			return "btn-danger";

		if (action.form_style == "primary")
			return "btn-primary";

		return "btn-default";
	};

	$scope.getUIActions = function(type) {
		if ($scope.data.disableUIActions)
			return [];
		if (type) {
			return $scope.data.f._ui_actions.filter(function(action) {
				// STRY0122589 - don't show Create Task if data.draftOnly is true
				var showButton = true;
				if(action.sys_id == '4a0a64badb9d1740bb8ee536ca961956' && c.data.draftOnly){
					showButton = false;
				}
				//We handle the primary action button separately.
				return showButton && !action.primary && action['is_' + type];
			});
		} else {
			return $scope.data.f._ui_actions;
		}
	};

	c.thisPage = $location.search()['id'];
	$scope.getPrimaryAction = function() {
		var primaryActions = $scope.data.f._ui_actions.filter(function(action) {

			return action.primary;
		});
		return (primaryActions.length) ? primaryActions[0] : null;
	};

	$scope.getUIActionContextMenu = function(event) {
		var menu = [];
		if (event.ctrlKey)
			return menu;

		var contextActions = $scope.getUIActions('context');
		contextActions.forEach(function(action) {
			menu.push([action.name, function() {
				$scope.triggerUIAction(action);
			}]);
		});

		if (contextActions.length > 0)
			menu.push(null);
		menu.push([$scope.data.exportPDFMsg, function() {
			exportPDF("");
		}]);
		menu.push([$scope.data.exportPDFLandMsg, function() {
			exportPDF('true');
		}]);

		return menu;
	};

	function exportPDF(landscape) {
		$window.open("/" + $scope.data.f.table + ".do?PDF&landscape=" + landscape + "&sys_id=" + $scope.data.sys_id + "&sysparm_view=" + $scope.data.f.view);
	}

	//trigger the primary UI Action on save (if there is one)
	var deregister = $scope.$on('$sp.save', function() {
		var primaryAction = $scope.getPrimaryAction();
		if (primaryAction)
			$scope.triggerUIAction(primaryAction);
	});
	$scope.$on('$destroy', function() {
		deregister();
	});

	$scope.triggerUIAction = function(action) {
		if ($scope.data.disableUIActions && !action.primary) {
			return;
		}
		$rootScope.$broadcast('sp.form.ui_action.triggered');
		if (action.action_name == 'createSchedule') {
			$('button[gsft_id="9a33e9b6db6e6380bb8ee536ca96190d"]').remove();
		}

		var activeElement = document.activeElement;
		if (activeElement) {
			activeElement.blur();
		}
		//-----------------------------
		$scope.$evalAsync(function() {

			if (g_form) {
				$scope.submitting = true;
				if (!g_form.submit(action.action_name || action.sys_id)) {
					$scope.submitting = false;
					$rootScope.$broadcast('sp.form.submit.failed', action);
				}

				// STRY0074663
				if ($scope.submitting == true && c.data.isModal) {
					$scope.$parent.$parent.$dismiss();
				} // 09.10
			} 
		});

	};

	function constructResponseHandler(response) {
		var showUpdate = true;
		// JS error occurring when response empty
		if(response){
			var notifications = response['$$uiNotification'];
			// STRY0040294 - added .length > 0.  This was erroring b/c notificatoins was not null, it was an empty array.
			// I looked in the root form.  It has this same problem.
			if (notifications && notifications.length > 0 && notifications[0].type == 'error') {
				showUpdate = false;
			}					

			return function() {
				$rootScope.$broadcast("sp.form.submitted", {
					sys_id: (response.isInsert) ? response.sys_id : $scope.data.sys_id
				});
				var message;
				var eventName = "sp.form.record.updated";
				if (response.isInsert) {
					message = $scope.data.recordAddedMsg;
					var search = $location.search();
					search.sys_id = response.sys_id;
					search.spa = 1;
					$location.search(search).replace();
				} else if (showUpdate == true) {
					message = $scope.data.updatedMsg;
				}
				$scope.data.hideRelatedLists = hideRelatedLists();
				$scope.$emit(eventName, $scope.data.f._fields);
				$rootScope.$broadcast(eventName, $scope.data.f._fields);
				$scope.status = message;
				spUtil.addTrivialMessage(message);
				$timeout(clearStatus, 2000);
			};
		}
	}

	var ctrl = this;
	// switch forms
	var unregister = $rootScope.$on('$sp.list.click', onListClick);

	$scope.$on("$destroy", function() {
		unregister();
	});

	function _save() {
		var primaryAction = $scope.getPrimaryAction();
		if (primaryAction)
			$scope.triggerUIAction(primaryAction);
	}

	function onListClick(evt, arg) {
		// STRY0108629
		if((arg.table == c.data.table || c.data.table == null) && 
		   c.data.sys_id != arg.sys_id){
			loadForm(arg.table, arg.sys_id);
		}
	}

	function loadForm(table, sys_id) {
		var f = {};
		$scope.data.table = f.table = table;
		$scope.data.sys_id = f.sys_id = sys_id;
		f.view = $scope.data.view;
		return $scope.server.update().then(function(){
			// DFCT0010343 - TUP - Filter was not working for OU Templates in Template LIst screen - issue introduced in 2.6
			initRecordWatcher(c.data.table, "sys_id=" + c.data.sys_id);

			afterLoadFormReturns();
		});
	}

	$rootScope.$on('$TaskerTaskList.click', function(e, parms) {
		var p = $scope.data.page_id;
		if (p == 'discovertasker_taskdetails') {
			onListClick(e, parms);
		}
	});

	function openRelatedList(e, queryString) {
		$location.search(queryString);
		e.preventDefault();
	}

	$scope.$on('spModel.fields.rendered', function() {
		if (ctrl.panels)
			ctrl.panels.removeClass('shift-out').addClass('shift-in');
	});

	var g_form;

	function initForm(gFormInstance) {

		if (gFormInstance.getTableName() == $scope.data.f.table) {
			g_form = gFormInstance;
			spNavStateManager.register($scope.data.table, _save, g_form);
			$scope.isPageReady = true;
			$timeout(function() {
				$rootScope.$emit('spModel.gForm.rendered', g_form);
			}, 175);
			/****************************************************************
					* The following removes the relevant sections from 'Form Configuration' table
					* DFCT0010583
					*/
			// STRY0119587
			if (!c.data.hideDocuments && c.data.DocIntON && (c.data.sys_id !=-1 && c.data.sys_id !='') &&
				(c.data.table == 'x_153465_discovert_route_task_instance' ||
				 c.data.table == 'x_153465_discovert_discover_routing_template' ||
				 c.data.table == 'x_153465_discovert_route_tasks')) {

				for (var i in $scope.data._docint_widget.config_form_sections) {
					var ui_section_name = $scope.data._docint_widget.config_form_sections[i];
					g_form.setSectionDisplay(ui_section_name, false);
				}
			}
			/****************************************************************/

		}
	}

	$scope.$on('spModel.gForm.initialized', function(e, gFormInstance) {
		initForm(gFormInstance);
		//STRY0056591: Get parent from the table calling the modal
		if ($scope.data.parent != undefined)
			if ($scope.data.parent.length > 0) {
				g_form.setValue('parent', $scope.data.parent);
			}
		// STRY0108170 - NOTE: this should pull all values off o a filter 
		if ($scope.data.u_ou_parent != undefined)
			if ($scope.data.u_ou_parent.length > 0) {
				g_form.setValue('u_ou_parent', $scope.data.u_ou_parent);
			}
		//REQUEST TYPE
		if ($scope.data.u_request_type != undefined && $scope.data.u_request_type.length > 0) {
			g_form.setValue('u_request_type', $scope.data.u_request_type);
		}
	});

	$scope.$on('spModel.gForm.env.created', function(e, gFormInstance) {
		initForm(gFormInstance);
	});

	// update the comments or worknotes based on activity stream
	$scope.$on("activity_stream_is_changed", function(event, data) {
		if (g_form && g_form.hasField(data.fieldName)) {
			g_form.setValue(data.fieldName, data.input);
			if (data.fieldToClear != "" && g_form.hasField(data.fieldToClear))
				g_form.setValue(data.fieldToClear, "");
		}
	});

	// Show or hide related lists
	$scope.$watch('data.f._related_lists', function() {
		$scope.data.hideRelatedLists = hideRelatedLists();

	}, true);

	function hideRelatedLists() {
		if (!$scope.data.f._related_lists)
			return true;
		if ($scope.options.hideRelatedLists == true)
			return true;
		if ($scope.data.sys_id == '-1')
			return true;
		// If all related lists are visible=false then hide
		if ($scope.data.f._related_lists.length > 0) {
			for (var i in $scope.data.f._related_lists) {
				var list = $scope.data.f._related_lists[i];
				if (list.visible) {
					return false;
				}
			}
		}
		return true;
	}

	function clearStatus() {
		$scope.status = "";
	}

	function setupAttachmentHandler() {
		$scope.attachmentHandler = new nowAttachmentHandler(appendDone, appendError);

		$scope.$evalAsync(function() {
			$scope.attachmentHandler.setParams($scope.data.table, $scope.data.f._attachmentGUID, 1024 * 1024 * $scope.data.maxAttachmentSize);
		});

		$scope.$on('dialog.upload_too_large.show', function(e) {
			$log.error($scope.data.largeAttachmentMsg);
			spUtil.addErrorMessage($scope.data.largeAttachmentMsg);
		});
	}

	function afterLoadFormReturns(){
		loadAttachmentsWidgets();
		loadDocIntWidgets();
		addActiveCssClass();
		setupAttachmentHandler();
		// Changed from page.title to data.f.title to remove post back
		if(c.data.sys_id != '-1'){
			top.document.title = c.data.f.title;
			$rootScope.$broadcast('sp.update.breadcrumbs', c.data.breadcrumbs);				
		}

	}

	function appendDone() {
		$scope.$broadcast("sp.attachments.update", $scope.data.f._attachmentGUID);
		spAriaUtil.sendLiveMessage($scope.data.attachmentSuccessMsg);
	}

	function appendError(error) {
		$scope.errorMessages.push(error);
		spUtil.addErrorMessage(error.msg + error.fileName);
	}

	if ($scope.data.f.title) {
		$scope.$emit('sp.widget-modal.set-aria-label', $scope.data.f.title);
	}
};

sp_widget.css:
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: KARINA TORRES 
//------------------------------------------------------------------------------------------------------------------------
//------------------------------------------------------------------------------------------------------------------------
// 2.5.21 | 09.10.2020 | KT | UI  | STRY0074067: TECH - Tasker - Unified CSS on widgets (Internal Story, PO story needed)
//------------------------------------------------------------------------------------------------------------------------


//------------------------------------------------------------------------------------------------------------------------
// CUSTOM    Some CSS selectors will be found in Tasker Overall Style Sheet
//------------------------------------------------------------------------------------------------------------------------

/* 2.7.2 | 2022-01-26 | mmcc | STRY0110656 - UI- Fixed Header and Button Bars on ALL Modals and lists
Have modal fit the viewport height with its own scrollbar start
*/
.dtech-modal-scroll-height-omit-header-required-info {
  max-height: calc(100vh - 352px);
  overflow-y: auto;
  padding-right: 15px;
}

.dtech-modal-scroll-height-omit-header-standard {
  max-height: calc(100vh - 272px);
  overflow-y: auto;
  padding-right: 15px;
}

.dtech-modal-scroll-height-required-info {
  max-height: calc(100vh - 525px);
  overflow-y: auto;
  padding-right: 15px;
}

.dtech-modal-scroll-height-standard {
  max-height: calc(100vh - 471px);
  overflow-y: auto;
  padding-right: 15px;
}
/* Have modal fit the viewport height with its own scrollbar end */

/* 2.7.2 | 2022-01-12 | mmcc | DFCT0010728 - Modal Scheduled Tasks shows title data with an ellipsis
flexbox ellipsis start 
*/
.container-menu-row {
  align-items: center;
  /* border: 2px solid pink; */
  column-gap: 5px;
  display: flex;
  flex-direction: row;
  width: 100%
}

.cell {
  flex: 1 1 auto;
  vertical-align: middle;
}

.col-1 {
  flex: 0 0 auto;
  vertical-align: middle;
}

.col-2 {
  display: flex;
  flex-direction: row;
  width: 40%;

  .title-ellipsised {
    flex: 1 2 auto;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }
}

.col-3 {
  display: flex;
  flex-direction: row;
  width: 45%;

  .title-ellipsised {
    flex: 1 2 auto;
    padding: 10px 10px 10px 0;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }
}

.col-5 {
  display: flex;
  flex-direction: row;
  justify-content: flex-end;
  /*width: 44%;*/
}

.col-7 {
  display: flex;
  flex-direction: row;
  justify-content: flex-end;
  width: 44%;
}

.col-8 {
  flex: 0 0 auto;
  vertical-align: middle;
  width: 30px;
}
/* flexbox ellipsis end */

/* 2.7.1 | 2021-12-15 | mmcc | DFCT0010716 - On Tabs (OU, Task) the icons did not align correctly with text at the top of the page */
.dtech-align-menu-text-icons {
  padding: 10px 0;
  vertical-align: middle;
}

.dtech-align-text-icons {
  padding-top: 10px;
  vertical-align: middle;
}

.dtech-align-icons-paperclip {
  padding-top: 5px;
}

// DFCT0010657
#loading-spinner {
  animation: loading 2s infinite linear;
}

@keyframes loading {
  from {
    transform: rotate(0deg);
  }
  to {
    transform: rotate(359deg);
  }
}

/* SECTIONS & FORMS */
//------------------------------------------------------------------------------------------------------------------------
.ng-isolate-scope .h4.ng-binding{
  font-weight: 400 !important;
  font-family: "SourceSansPro", Helvetica, Arial, sans-serif; //'Lucida Sans Unicode';
  padding-left: 5px;
  border-left-style: solid;
  border-left-color: $primary;
  border-left-width: 5px;
  color: $primary;
  padding-top: 8px;
  padding-bottom: 5px;
}

fieldset.ng-scope{
  margin-top: 5px;
}

label{
  //font-weight: 100!important;
  color: $primary;
}


/* DURATION */
//------------------------------------------------------------------------------------------------------------------------

#dur-minutes,
#dur-seconds { 
  visibility: hidden!important;
}

#dur-days,
#dur-hours { 
  width: 40px!important
}


/*
Set Classification color for banner (aka rectangle)
2.7.0 | 2021-08-10 | mmcc | STRY0104983 - Stretch- Technical Debt - Update CSS to organize into proper hierarchy of CSS
See Tasker Theme and CSS include: Classification Banner CSS Include
.taskform-classification-banner 
*/

/*
Set Restricted Group color for banner (aka rectangle)
2.7.0 | 2021-08-09 | mmcc | STRY0104884 Badges do not pass 508/WCAG compliance
See Tasker Theme and CSS include: Restricted Group Banner Style Sheet
.dtech-restricted-group-banner
*/



//------------------------------------------------------------------------------------------------------------------------
// OOTB FORM WIDGET
//------------------------------------------------------------------------------------------------------------------------

/* 2.7.1 | 2021-12-15 | mmcc | DFCT0010716 - On Tabs (OU, Task) the icons did not align correctly with text at the top of the page */
.btn-form-menu {
  /* vertical-align: inherit;
  padding: inherit; */
  background: none;
  padding: 10px 0;
}

.panel-title {
  word-wrap: break-word;
}

.panel-heading {
  .dropdown-menu {
    a {
      white-space: normal;
    }
  }
}

/*
2.7.0 | 2021-10-29 | mmcc | STRY0110472 - Stretch- 508 Compliant- Delete Buttons- (ALL Red buttons)
.dtech-field-error-label {} replaces below; Find it in Tasker Theme > Tasker Form Error Overrides Style Sheet
This widget is not using the below CSS selector
.sc-field-error-label {
margin-right: .5em;
display: inline-block;
background-color: $sc-field-error-color;
}
*/

.comment {
  font-weight: bold;
  margin-top: 2px;
  margin-bottom: 2px;
}
.mce-panel, .mce-btn {
  background-image: none;
  background-color: #f0f3f4;
}

.action-btn {
  margin-right: 5px;
}

/* 2.7.2 | 2022-01-26 | mmcc | STRY0110656 - UI- Fixed Header and Button Bars on ALL Modals and lists
Have modal fit the viewport height with its own scrollbar start
*/
.timeline-container {
  /* max-height: 50vh; */
  max-height: calc(100vh - 611px);
  height: 100%;
  overflow-y: auto;
}


.panel .panel {
  height: auto !important;
  /* 2.7.0 | 2021-06-23 | mmcc | STRY0079333 Tasker Split View - My Documents and Shared Documents tab error */
  position: relative;
}

.attachment-button {
  .glyphicon-paperclip {
    font-size: 18px;
  }
}

.dropdown {
  .glyphicon-menu-hamburger:focus {
    outline: thin dotted;
    outline: 5px auto $input-border-focus;
    outline-offset: -2px; 
  }
}

.empty-state-wrapper {
  width: 100%;
  height: 100%;
  align-items: center;
  display: flex;
  flex-direction: column;
  padding: 10vh 20px 20px;

  .empty-state {
    border: 1px solid #e7e9eb;
    border-radius: 10px;
    max-width: 700px;
    padding: 30px 40px 20px;
    position: relative;

    .empty-state-badge {
      top: -36px;
      left: 50%;
      position: absolute;
      height: 72px;
      width: 72px;
      -webkit-align-items: center;
      -ms-flex-align: center;
      align-items: center;
      border-radius: 100%;
      color: #ffffff;
      display: -webkit-flex;
      display: -ms-flexbox;
      display: flex;
      font-size: 40px;
      -webkit-justify-content: center;
      -ms-flex-pack: center;
      justify-content: center;
      margin-left: -36px;
      text-align: center;
    }

    .empty-state-header {
      font-size: 30px;
      text-align: center;
      color: #343d47;
    }

    .empty-state-content {
      ul {
        list-style: disc outside;
        margin: 0 0 10px 0;
        padding: 0 0 0 30px;
      }
    }
  }
}

.text-success-alt {
  background-color: $state-success-text;
}

.text-info-alt {
  background-color: $state-info-text;
}

sp_widget.script:
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: KARINA TORRES
// WIDGET BASE: FORM
//------------------------------------------------------------------------------------------------------------------------
//
// 2.7.0 | 2021-05-11 | mmcc | STRY0099400 Remove the icon for going to the split view screen
//                                         Changes made in HTML
// 2.7.0 | 2021-05-18 | raj  | STRY0082332 FIX: Template Designers can create Template Schedules
//                                         Changes in Server Script
// 2.7.0 | 2021-05-21 | mmcc | STRY0099596 Record Watcher on Template Count not Updating
//											emit sends rowCount in params, no need for .Deleted or .Added
//											Change made in Client controller
// 2.7.0 | 2021-05-25 | mmcc | STRY0090508 When Tasker Users click "UI Policies" or "Client Scripts" on the context menu 
// 											they are redirected to a security constraint error
//                                          Changes in HTML and Server Script
// 2.7.0 | 2021-06-23 | mmcc | STRY0079333 Tasker Split View - My Documents and Shared Documents tab error 
// 											In Server Script, formatted file and added missing semicolon
//                                          Changes in CSS and Server Script
// 2.7.0 | 2021-07-25 | raj  | STRY0101803 - changed the split view and needed to remove classification badge form bottom in split view
//																					Changes in HTML only
// 2.7.0 | 2021-07-31 | raj | STRY0079002: FIX: STRETCH- "Paperclip" icon appears in Tasker "Split View", split view page should not show attachment button
//																					Changes in HTML only
// 2.7.0 | 2021-08-09 | mmcc | STRY0104884 Badges do not pass 508/WCAG compliance
// 											In HTML, change CSS selector .assignmentgroup-banner to use .dtech-restricted-group-banner.
// 											In CSS, selector .assignmentgroup-banner removed. Comment added for   
// 											 .dtech-restricted-group-banner to direct to Tasker Theme
//											 then CSS include: Restricted Group Banner CSS Include.
//                                          Changes in HTML and CSS
// 2.7.0 | 2021-08-10 | mmcc | STRY0104983 - Stretch- Technical Debt - Update CSS to organize into proper hierarchy of CSS
// 											In CSS, selector .taskform-classification-banner declaration removed. Comment added to direct 
// 											 to Tasker Theme then CSS include: Classification Banner CSS Include.
//											 Selector #sp_formfield_status declaration removed, was commented out.
//                                          Changes in CSS
// 2.7.0 | 2021-08-20 | raj  | STRY0108140 -Task Form Preferences - Button Update
//														- This is a technical story to account for the time taken to update the buttons
//                                          Changes in HTML and Client Script
// 2.7.0 | 2021-08-20 | raj  | STRY0105742 -DIA- Organizational Hierarchy Visual Indicators – OU Unit Icon for OUHA
//                                          Changes in HTML
// 2.7.0 | 2021-08-25 | raj  | STRY0107408 -DIA- Org Hierarchy– Request Update Button 
//                                          Added New Button on Data Table at list top
//                                          Changes in Server Script
//                           | no stoyr, but udpated stylying on all buttons to Use OOTB ServiceNow class settings
//                                          Changes in Client Script
// 2.7.0 | 2021-08-26 | raj  | STRY0108170 -DIA- Org Hierarchy– Hierarchy Request Form
//                                          Changes in Server Script and Client Script
// 2.7.0 | 2021-08-21 | raj  | STRY0108599 - Removed the full screen from this widget for Organizational Hierarchy.
// 2.7.0 | 2021-08-30 | raj  | STRY0108629 - bifold settings
// 2.7.0 | 2021-09-07 | mmcc | STRY0105158 - After creation of a new template, redirect is showing the wrong widget on the right column
// 											In Server script, After creating a new Template from the Home page, trap on the page id 
// 											 and table then get the Top Task sys_id and change the the table to route tasks.
//                                          Changes in Server script
// 2.7.0 | 2021-08-30 | raj  | STRY0111049 - Standard Task Form Widget Updater – Placeholder Story
// 2.7.0 | 2021-10-04 | raj  | STRY0105791 - Simple Task Forms- Placeholder Story
//																				Changes in Server and Client Script
// 2.7.0 | 2021-10-8 | mmcc | STRY0109110 - Draft Scheduled Tasks – UI – Delete Modal- Add Descendant tasks count
//											In Service script, Added code to get data.parent_id from rec.getValue('parent')
//											In Client controller, updated watcherChannel subscribe to handle move to parent or redirect
//                                          Changes in Server script and Client controller
//
// 2.7.0 | 2021-10-12 | raj   | STRY0112002 - Task Form Page- Add a "Create Subtask" icon
